d['en']['legal.privacy.text_1']='Privacy Policy';
d['en']['legal.privacy.text_2']='Last updated: January 2026';
d['en']['legal.privacy.text_3']='This Privacy Policy describes how Chatura Indonesia ("we," "our," or "us") collects, uses, and protects your personal information when you visit our website.';
d['en']['legal.privacy.text_4']='Information We Collect';
d['en']['legal.privacy.text_5']='We may collect information you provide directly, such as your name, email address, and professional details when you contact us or subscribe to our communications.';
