d['en']['legal.privacy.text_7']='We use your information to respond to inquiries, provide professional services, and improve our website experience.';
d['en']['legal.privacy.text_8']='Contact Us';
d['en']['legal.terms.text_1']='Terms of Use';
d['en']['legal.terms.text_2']='Last updated: January 2026';
d['en']['legal.terms.text_3']='Welcome to the Chatura Indonesia website. By accessing or using this website, you agree to be bound by these Terms of Use.';
d['en']['legal.terms.text_4']='Use of Website';
d['en']['legal.terms.text_5']='This website is provided for general informational purposes only. The content does not constitute professional advice and should not be relied upon as such.';
d['en']['legal.terms.text_6']='Intellectual Property';
d['en']['legal.terms.text_7']='All content on this website, including text, graphics, logos, and images, is the property of Chatura Indonesia and is protected by applicable intellectual property laws.';
