d['en']['legal.terms.text_10']='Contact Us';
d['en']['legal.cookies.text_1']='Cookies Policy';
d['en']['legal.cookies.text_2']='Last updated: January 2026';
d['en']['legal.cookies.text_3']='This Cookies Policy explains how Chatura Indonesia uses cookies and similar technologies when you visit our website.';
d['en']['legal.cookies.text_4']='What Are Cookies';
d['en']['legal.cookies.text_5']='Cookies are small text files stored on your device when you visit a website. They help us understand how you use our site and improve your experience.';
d['en']['legal.cookies.text_6']='How We Use Cookies';
d['en']['legal.cookies.text_7']='We use cookies for analytics, functionality, and to remember your preferences. We do not use cookies for advertising purposes.';
d['en']['legal.cookies.text_8']='Managing Cookies';
d['en']['legal.cookies.text_9']='You can control cookies through your browser settings. Disabling certain cookies may affect website functionality.';
d['en']['legal.cookies.text_10']='Contact Us';
d['en']['legal.disclaimer.text_1']='Disclaimer';
d['en']['legal.disclaimer.text_2']='Last updated: January 2026';
d['en']['legal.disclaimer.text_3']='The information provided on the Chatura Indonesia website is for general informational purposes only. While we endeavor to keep the information up to date and correct, we make no representations or warranties of any kind about the completeness, accuracy, reliability, or availability of the information.';
d['en']['legal.disclaimer.text_4']='Professional Advice';
