d['en']['legal.code_of_conduct.text_3']='Chatura Indonesia is committed to maintaining the highest standards of ethical business practices and professional conduct. This Code of Conduct applies to all partners, employees, and contractors.';
d['en']['legal.code_of_conduct.text_4']='Integrity';
d['en']['legal.code_of_conduct.text_5']='We conduct our business with honesty, transparency, and fairness. We comply with all applicable laws and regulations in every jurisdiction where we operate.';
d['en']['legal.code_of_conduct.text_6']='Professional Standards';
d['en']['legal.code_of_conduct.text_7']='We maintain the highest standards of professional competence and care in delivering our services. We continuously develop our skills and knowledge.';
d['en']['legal.code_of_conduct.text_8']='Confidentiality';
d['en']['legal.code_of_conduct.text_9']='We protect the confidentiality of our clients\' information and do not use it for personal gain or disclose it to unauthorized parties.';
